// Example: Frontend Axios interceptor for attaching token
// client/src/utils/axiosInstance.js
import axios from 'axios';

const instance = axios.create({
  baseURL: 'http://localhost:5000/api',
  withCredentials: true // Important for sending cookies
});

instance.interceptors.request.use(
  config => {
    // Retrieve token from localStorage, or wherever it's stored
    const token = localStorage.getItem('accessToken'); 
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  error => Promise.reject(error)
);

instance.interceptors.response.use(
  response => response,
  error => {
    // Global handling for 401s, e.g., redirect to login
    if (error.response && error.response.status === 401) {
      console.warn('Authentication expired or invalid. Redirecting to login.');
      // window.location.href = '/login'; // Or use React Router's navigate
    }
    return Promise.reject(error);
  }
);

export default instance;

