export const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Expected: 'Bearer TOKEN'

  if (token == null) {
    console.warn('Auth: Token missing for request to', req.originalUrl);
    return res.status(401).json({ message: 'Authentication token required.' });
  }

  jwt.verify(token, env.JWT_SECRET, (err, user) => {
    if (err) {
      console.warn('Auth: Token verification failed for', req.originalUrl, '-', err.message);
      if (err.name === 'TokenExpiredError') {
        return res.status(401).json({ message: 'Authentication token expired.' });
      }
      return res.status(403).json({ message: 'Invalid authentication token.' });
    }
    req.user = user;
    next();
  });
};

