const jwt = require('jsonwebtoken');
const asyncHandler = require('express-async-handler');
const { db } = require('../db');
const { users } = require('../db/schema');
const { eq } = require('drizzle-orm');

const protect = asyncHandler(async (req, res, next) => {
    let token;

    if (req.headers.authorization && req.headers.authorization.startsWith('Bearer')) {
        try {
            token = req.headers.authorization.split(' ')[1];
            console.log('[Auth Middleware] Token received:', token ? 'YES' : 'NO', token.substring(0, 10) + '...'); // Log partial token for debug

            // Verify token
            const decoded = jwt.verify(token, process.env.JWT_SECRET);
            console.log('[Auth Middleware] Token decoded payload:', decoded); // Log decoded payload

            // Fetch user from DB based on decoded ID
            const user = await db.select({
                id: users.id,
                email: users.email,
                role: users.role
            })
            .from(users)
            .where(eq(users.id, decoded.id))
            .limit(1);

            if (user.length === 0) {
                console.warn('[Auth Middleware] User not found for ID:', decoded.id);
                res.status(401);
                throw new Error('Not authorized, user not found');
            }

            req.user = user[0];
            next();
        } catch (error) {
            console.error('[Auth Middleware] Error during token verification:', error.message, error.name); // Detailed error logging
            if (error.name === 'TokenExpiredError') {
                res.status(401);
                throw new Error('Not authorized, token expired');
            } else if (error.name === 'JsonWebTokenError') {
                res.status(401);
                throw new Error('Not authorized, invalid token');
            } else {
                res.status(401);
                throw new Error('Not authorized, token processing failed');
            }
        }
    } else {
        console.warn('[Auth Middleware] No Authorization header or malformed header.');
        res.status(401);
        throw new Error('Not authorized, no token provided');
    }
});

module.exports = { protect };
