import React, { createContext, useContext, useState, useEffect } from 'react';
import { useLocation } from 'react-router-dom'; // Assuming react-router-dom is used for routing
import api from '../utils/api'; // Assuming an API utility for fetch/axios requests

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const location = useLocation(); // Get current path to check route context

  useEffect(() => {
    const checkAuthStatus = async () => {
      // Define paths where an initial authentication check is unnecessary or problematic
      const unauthenticatedPaths = ['/register', '/login', '/forgot-password', '/reset-password'];

      // If on one of these paths, and no explicit login/registration attempt is ongoing,
      // skip the global /api/auth/me check to avoid unnecessary 401s.
      if (unauthenticatedPaths.includes(location.pathname)) {
        setLoading(false);
        return; // Do not try to fetch user info if on an unauthenticated entry page
      }

      // Check for an existing token (e.g., from localStorage or cookies)
      const token = localStorage.getItem('authToken'); // Or whatever storage mechanism CoAIleague uses

      if (!token) {
        setUser(null);
        setLoading(false);
        return; // No token, so no user is logged in, no need to call /api/auth/me
      }

      try {
        // If a token exists and not on an unauthenticated path, attempt to fetch user details
        // The 'api' utility would typically include the token in its headers automatically.
        const response = await api.get('/api/auth/me'); 
        setUser(response.data); // Assuming response.data contains user object
      } catch (error) {
        console.error('Failed to fetch user data or token invalid:', error);
        // If there's an error (e.g., 401 for expired/invalid token), clear stored token
        localStorage.removeItem('authToken');
        setUser(null);
      } finally {
        setLoading(false);
      }
    };

    checkAuthStatus();
  }, [location.pathname]); // Re-run this effect when the URL path changes

  // Include login, logout, register functions as part of the context value
  const authContextValue = {
    user,
    setUser,
    loading,
    // ... other auth methods like login, logout, register
  };

  return (
    <AuthContext.Provider value={authContextValue}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);
