// const { db, users } = require('../db/schema'); // Example for Drizzle ORM
// const { eq } = require('drizzle-orm');

module.exports = async (req, res, next) => {
  let token;

  // 1. Check for Bearer token in Authorization header
  if (req.headers.authorization && req.headers.authorization.startsWith('Bearer')) {
    try {
      token = req.headers.authorization.split(' ')[1];
      const decoded = jwt.verify(token, process.env.JWT_SECRET); // Crucial verification step
      // req.user = await db.select().from(users).where(eq(users.id, decoded.id)).limit(1);
      next();
    } catch (error) {
      console.error('Token verification failed (Header):', error.message); // Log error for debugging
      return res.status(401).json({ message: 'Not authorized, token failed' });
    }
  }
  // 2. Fallback: Check for JWT in HttpOnly cookie (if used)
  else if (req.cookies && req.cookies.jwt) {
    try {
      token = req.cookies.jwt;
      const decoded = jwt.verify(token, process.env.JWT_SECRET);
      // req.user = await db.select().from(users).where(eq(users.id, decoded.id)).limit(1);
      next();
    } catch (error) {
      console.error('Token verification failed (Cookie):', error.message);
      return res.status(401).json({ message: 'Not authorized, invalid cookie token' });
    }
  }

  // If no token found at all
  if (!token) {
    return res.status(401).json({ message: 'Not authorized, no token provided' });
  }
};

// --- client/src/api/authService.js (Example client-side API call) ---
import axios from 'axios';

const API_BASE_URL = 'http://localhost:5000/api'; // Or just '/api' if using Vite proxy

export const getCurrentUser = async () => {
  const token = localStorage.getItem('jwtToken'); // Or obtain from sessionStorage/cookie logic
  if (!token) {
    throw new Error('No authentication token found.');
  }

  try {
    const response = await axios.get(`${API_BASE_URL}/auth/me`, {
      headers: {
        Authorization: `Bearer ${token}`,
      },
      // withCredentials: true, // Uncomment if using HttpOnly cookies and different origins
    });
    return response.data;
  } catch (error) {
    console.error('Failed to fetch current user:', error);
    throw error;
  }
};
